import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { spawnSync } from 'node:child_process'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))

const TSX = path.join(__dirname, '..', '..', '..', '..', 'node_modules', '.bin', 'tsx')
const RUN = path.join(__dirname, '..', 'run.ts')

function run(
  args: string[] = [],
  env: Record<string, string> = {},
): { status: number | null; stdout: string; stderr: string } {
  return spawnSync(TSX, [RUN, ...args], {
    encoding: 'utf8',
    env: { ...process.env, ...env },
  })
}

describe('status command', () => {
  it('exits 0 with no token set', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.strictEqual(result.status, 0, `expected exit 0, got ${result.status}\n${result.stderr}`)
  })

  it('stdout contains NOT SET when no token', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.ok(result.stdout.includes('NOT SET'), `expected "NOT SET" in stdout:\n${result.stdout}`)
  })

  it('stdout contains masked token when token is set', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: 'phx_supersecrettoken123' })
    assert.ok(
      result.stdout.includes('***'),
      `expected masked token "***" in stdout:\n${result.stdout}`,
    )
    assert.ok(
      !result.stdout.includes('supersecrettoken123'),
      'token value must not appear in plaintext',
    )
  })

  it('stdout is valid JSON', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '' })
    assert.doesNotThrow(
      () => JSON.parse(result.stdout),
      `stdout is not valid JSON:\n${result.stdout}`,
    )
  })

  it('includes project_id in output', () => {
    const result = run(['status'], { POSTHOG_PERSONAL_API_KEY: '', POSTHOG_PROJECT_ID: '39507' })
    const parsed = JSON.parse(result.stdout) as { project_id: unknown }
    assert.ok(parsed.project_id, 'output must include project_id')
  })
})

/**
 * Integration sequence — runs the full safe verification in order.
 * Only executes when POSTHOG_TEST_LIVE=1.
 */

import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { spawnSync } from 'node:child_process'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))

const LIVE = Boolean(process.env['POSTHOG_TEST_LIVE'])

const TSX = path.join(__dirname, '..', '..', '..', '..', 'node_modules', '.bin', 'tsx')
const RUN = path.join(__dirname, '..', 'run.ts')

function run(args: string[] = []): { status: number | null; stdout: string; stderr: string } {
  return spawnSync(TSX, [RUN, ...args], {
    encoding: 'utf8',
    env: { ...process.env },
    timeout: 30000,
  })
}

describe('live integration sequence (POSTHOG_TEST_LIVE=1)', { skip: !LIVE }, () => {
  it('status exits 0 and token_present is true', () => {
    const result = run(['status'])
    assert.strictEqual(result.status, 0, `stderr: ${result.stderr}`)
    const parsed = JSON.parse(result.stdout) as { token_present: boolean }
    assert.strictEqual(parsed.token_present, true, 'token_present must be true')
  })

  it('inspect --live exits 0', () => {
    const result = run(['inspect', '--live'])
    assert.strictEqual(result.status, 0, `stderr: ${result.stderr}`)
  })

  it('compare exits 0', () => {
    const result = run(['compare'])
    assert.strictEqual(result.status, 0, `stderr: ${result.stderr}`)
  })

  it('create exits 0', () => {
    const result = run(['create'])
    assert.strictEqual(result.status, 0, `stderr: ${result.stderr}`)
  })

  it('create again exits 0 with all tiles existing (idempotency)', () => {
    const result = run(['create'])
    assert.strictEqual(result.status, 0, `stderr: ${result.stderr}`)
    const parsed = JSON.parse(result.stdout) as { tiles: Array<{ status: string }> }
    const nonExisting = parsed.tiles.filter((t) => t.status !== 'existing')
    assert.strictEqual(
      nonExisting.length,
      0,
      `expected all tiles "existing" on second run: ${JSON.stringify(nonExisting)}`,
    )
  })
})

import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { readFileSync } from 'node:fs'
import { resolve, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

import { createClient } from '../lib/posthog-client.js'
import { getFixture } from '../lib/fixtures.js'

const __dirname = dirname(fileURLToPath(import.meta.url))

describe('dead exports: DashboardSpec interface', () => {
  it('dashboard-spec.ts does not export DashboardSpec interface', () => {
    const src = readFileSync(
      resolve(__dirname, '../lib/dashboard-spec.ts'),
      'utf8',
    )
    assert.ok(
      !src.includes('export interface DashboardSpec'),
      'DashboardSpec interface must not be exported from dashboard-spec.ts',
    )
  })
})

describe('dead exports: patchDashboard on client', () => {
  it('client object does not expose patchDashboard', () => {
    const client = createClient({
      host: 'http://localhost',
      projectId: 'test',
      token: 'test-token',
    })
    assert.ok(
      !('patchDashboard' in client),
      'patchDashboard must not be a property of the PostHogClient object',
    )
  })
})

describe('dead exports: fixture keys status and inspect-live', () => {
  it('getFixture("status") throws', () => {
    assert.throws(
      () => (getFixture as (key: string) => unknown)('status'),
      /No fixture for command: status/,
      'getFixture("status") must throw — "status" fixture key should be removed',
    )
  })

  it('getFixture("inspect-live") throws', () => {
    assert.throws(
      () => (getFixture as (key: string) => unknown)('inspect-live'),
      /No fixture for command: inspect-live/,
      'getFixture("inspect-live") must throw — "inspect-live" fixture key should be removed',
    )
  })
})

